Code:
public String atFirst(String str) {
    if (str == null || str.length() == 0) {
        return "@" + "@";
    }
    if (str.length() == 1) {
        return str + "@";
    }
    if (str.length() < 2) {
        return str + "@";
    }
    return str.substring(0, 2);
}

public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

